SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vr_wef_smt (membership_no, approve_date, mem_age, smt_date, piad_date) AS select membership_no

, approve_date 
, date_trunc('day', mem_age/12)
, pka_srv_datetime.fp_RelativeMonth( approve_date  , mem_age  )  as smt_date 
, PKA_WEF_REQ_SMT.fp_cals_paid_rate(  mem_age   )   as paid_rate
 FROM ( 
SELECT sc_mem_m_membership_registered.membership_no   

         , sc_mem_m_membership_registered.approve_date        
	  , pka_srv_datetime.fp_MonthsAfter( sc_mem_m_membership_registered.approve_date 	,  to_date( '!cal_date_1!' )    ) as mem_age
      , to_date( '!cal_date_1!' )   as cal_date 

        FROM sc_mem_m_membership_registered  
        WHERE sc_mem_m_membership_registered.member_status_code = '0'
        AND member_group_no between   '11000001' and    '9500'
         AND member_group_no <> '9499'
         AND member_group_no <> '9498'

        ORDER BY sc_mem_m_membership_registered.membership_no
) TabSMT 
where 1=1
/*WHERE*/

--and  pka_srv_datetime.fp_MonthsAfter(   TabSMT.approve_date  ,  to_date( '!cal_date_1!' ) )  >= 420   --mem age Over 10 Year
;

